#include <stdio.h>

void rgb_to_ycbcr(int r, int g, int b, int* y, int* cb, int* cr) {
 *y = (int)(0.299*r + 0.587*g + 0.114*b);
 *cb = (int)(0.564*(b - *y));
 *cr = (int)(0.713*(r - *y));
}

int main() {
 int r = 255, g = 0, b = 0;
 int y, cb, cr;
 rgb_to_ycbcr(r, g, b, &y, &cb, &cr);
 printf("Y: %d, Cb: %d, Cr: %d\n", y, cb, cr);
 return 0;
}
